import { createClient } from "@/lib/supabase/server";
import { redirect } from "next/navigation";
import type { Metadata } from "next";
import Link from "next/link";
import { EnterpriseCard, EnterpriseStat } from "@/components/ui/EnterpriseCard";

export const metadata: Metadata = { title: "Pacientes" };

async function getPatientsData(therapistId: string) {
  const supabase = await createClient();

  const [patientsResult, sessionsCountResult] = await Promise.all([
    supabase
      .from("patients")
      .select("id, name, email, status, tags, mood_score, telegram_username, created_at, updated_at")
      .eq("therapist_id", therapistId)
      .not("status", "eq", "archived")
      .order("updated_at", { ascending: false }),

    supabase
      .from("sessions")
      .select("patient_id")
      .eq("therapist_id", therapistId),
  ]);

  const patients = patientsResult.data ?? [];
  const sessionCounts: Record<string, number> = {};
  for (const s of sessionsCountResult.data ?? []) {
    sessionCounts[s.patient_id] = (sessionCounts[s.patient_id] ?? 0) + 1;
  }

  return { patients, sessionCounts };
}

const STATUS_CONFIG: Record<
  string,
  { label: string; badgeClass: string; dotClass: string }
> = {
  new: {
    label: "Novo",
    badgeClass: "border-[#38bdf8]/40 bg-[#38bdf8]/10 text-[#38bdf8]",
    dotClass: "bg-[#38bdf8] shadow-[0_0_8px_#38bdf8]",
  },
  active: {
    label: "Ativo",
    badgeClass:
      "border-[rgba(82,183,136,.4)] bg-[rgba(82,183,136,.12)] text-[var(--color-brand)]",
    dotClass: "bg-[var(--color-brand)] shadow-[0_0_8px_var(--color-brand)]",
  },
  inactive: {
    label: "Inativo",
    badgeClass:
      "border-[var(--color-border-strong)] bg-[var(--color-surface-hover)] text-[var(--color-text-muted)]",
    dotClass: "bg-[var(--color-text-muted)]",
  },
  lead: {
    label: "Lead",
    badgeClass: "border-[#fbbf24]/40 bg-[#fbbf24]/10 text-[#fbbf24]",
    dotClass: "bg-[#fbbf24] shadow-[0_0_8px_#fbbf24]",
  },
};

function initials(name: string): string {
  const parts = name.trim().split(/\s+/);
  if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();
  return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
}

export default async function PacientesPage() {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) redirect("/auth/login");

  const { data: therapist } = await supabase
    .from("therapists")
    .select("id")
    .eq("user_id", user.id)
    .single();
  if (!therapist) redirect("/auth/login");

  const { patients, sessionCounts } = await getPatientsData(therapist.id);

  const active = patients.filter(p => p.status === "active").length;
  const newPatients = patients.filter(p => p.status === "new").length;
  const leads = patients.filter(p => p.status === "lead").length;

  return (
    <div className="p-8 max-w-7xl mx-auto space-y-8 animate-[fadeUp_.4s_ease-out_both] w-full">
      {/* Header */}
      <div className="flex justify-between items-end mb-4">
        <div className="flex flex-col gap-1">
          <h1 className="font-[family-name:var(--font-display)] text-[40px] font-light text-[var(--color-text-primary)] tracking-tight leading-none">
            Pacientes
          </h1>
          <p className="text-[15px] font-light text-[var(--color-text-muted)] mt-1.5">
            {patients.length} total · {active} ativos · {newPatients} novos · {leads} leads
          </p>
        </div>
        <button type="button" className="px-5 py-2.5 bg-[var(--color-brand)] text-[#060E09] rounded-xl text-[14px] font-medium hover:bg-opacity-90 hover:scale-[1.02] transition-all duration-300 shadow-[0_0_20px_rgba(82,183,136,0.2)]">
          + Novo Paciente
        </button>
      </div>

      {/* Summary cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-5">
        <EnterpriseStat delay={0.05} label="Total" value={String(patients.length)} />
        <EnterpriseStat delay={0.1} label="Ativos" value={String(active)} />
        <EnterpriseStat delay={0.15} label="Novos (30d)" value={String(newPatients)} />
        <EnterpriseStat delay={0.2} label="Leads" value={String(leads)} />
      </div>

      {/* Patients list */}
      <EnterpriseCard delay={0.3} className="p-0 overflow-hidden w-full glass-panel">
        {/* Table header */}
        <div className="grid grid-cols-[2.5fr_1fr_1fr_1fr_1fr] px-6 py-5 border-b border-[var(--color-border-subtle)] text-[11px] text-[var(--color-text-muted)] tracking-widest uppercase font-medium bg-[var(--color-surface)]/50">
          <span>Paciente</span>
          <span>Status</span>
          <span>Sessões</span>
          <span>Humor</span>
          <span>Atualizado</span>
        </div>

        {patients.length === 0 ? (
          <div className="p-16 text-center text-[var(--color-text-muted)] flex flex-col items-center justify-center gap-3">
            <span className="text-4xl opacity-50">👥</span>
            <p className="text-[15px] font-light">Nenhum paciente ainda. Adicione seu primeiro paciente!</p>
          </div>
        ) : (
          <div className="flex flex-col">
            {patients.map((patient, i) => {
              const statusCfg = STATUS_CONFIG[patient.status] ?? STATUS_CONFIG.inactive;
              const sessions = sessionCounts[patient.id] ?? 0;
              const updatedAt = new Date(patient.updated_at).toLocaleDateString("pt-BR", { day: "2-digit", month: "2-digit" });
              const mood = patient.mood_score;

              return (
                <Link key={patient.id} href={`/dashboard/pacientes/${patient.id}`} className="block group relative">
                  <div className={`grid grid-cols-[2.5fr_1fr_1fr_1fr_1fr] px-6 py-5 items-center transition-all duration-300 group-hover:bg-[var(--color-surface-hover)] relative z-10
                    ${i < patients.length - 1 ? "border-b border-[var(--color-border-subtle)]" : ""}`}
                  >
                    {/* Patient */}
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 rounded-full shrink-0 flex items-center justify-center font-[family-name:var(--font-display)] text-[14px] text-[var(--color-brand)] font-light border-[1.5px] border-[var(--color-brand)]/30 bg-[var(--color-brand)]/10 group-hover:border-[var(--color-brand)]/50 transition-colors shadow-inner">
                        {initials(patient.name)}
                      </div>
                      <div className="flex flex-col">
                        <div className="text-[15px] text-[var(--color-text-primary)] font-medium group-hover:text-white transition-colors tracking-wide">
                          {patient.name}
                        </div>
                        <div className="text-[13px] text-[var(--color-text-muted)] font-light mt-0.5">
                          {patient.email}
                          {patient.telegram_username && (
                            <span className="text-sky-400 ml-2 font-medium">@{patient.telegram_username}</span>
                          )}
                        </div>
                      </div>
                    </div>

                    {/* Status */}
                    <div>
                      <span
                        className={`text-[11px] px-3 py-1 rounded-full border inline-flex items-center gap-2 w-fit font-medium ${statusCfg.badgeClass}`}
                      >
                        <span className={`w-1.5 h-1.5 rounded-full ${statusCfg.dotClass}`} />
                        {statusCfg.label}
                      </span>
                    </div>

                    {/* Sessions */}
                    <div className="text-[14px] text-[var(--color-text-secondary)] font-light">
                      {sessions} sessões
                    </div>

                    {/* Mood */}
                    <div>
                      {mood !== null && mood !== undefined ? (
                        <div className="flex items-center gap-1.5">
                          {[1, 2, 3, 4, 5].map((n) => (
                            <div
                              key={n}
                              className={`w-1.5 h-1.5 rounded-full transition-colors duration-300 ${n <= mood ? "bg-[var(--color-brand)] shadow-[0_0_6px_var(--color-brand)]" : "bg-[var(--color-border-strong)]"}`}
                            />
                          ))}
                          <span className="text-[12px] text-[var(--color-text-muted)] ml-2 font-medium">{mood}/5</span>
                        </div>
                      ) : (
                        <span className="text-[13px] text-[var(--color-text-muted)] font-light">—</span>
                      )}
                    </div>

                    {/* Updated */}
                    <div className="text-[13px] text-[var(--color-text-muted)] font-light">{updatedAt}</div>
                  </div>
                  <div className="absolute inset-0 border-l-[3px] border-transparent group-hover:border-[var(--color-brand)] transition-colors z-20 pointer-events-none" />
                </Link>
              );
            })}
          </div>
        )}
      </EnterpriseCard>
    </div>
  );
}
